// ----- File: src/utils/math.ts -----
// Export a function so other files can use it
export function calculateTotal(items: number[]): number {
  // Sum all numbers in the array using reduce
  return items.reduce((sum, item) => sum + item, 0);
}
// Export a constant value
export const TAX_RATE: number = 0.08;
// Default export — one per module
// ----- File: src/main.ts -----
// Import the named exports and the default export
import { calculateTotal, TAX_RATE } from './utils/math.js';
// Use the imported function and constant
const prices: number[] = [29.99, 49.99, 15.00];
const subtotal: number = calculateTotal(prices);
const tax: number = subtotal * TAX_RATE;
console.log(`Subtotal: $${subtotal}, Tax: $${tax.toFixed(2)}`);
// Expected: Subtotal: $94.98, Tax: $7.60
